def canonical_bytes(value: Any) -> bytes:
    return (json.dumps(value, sort_keys=True, separators=(",", ":"), ensure_ascii=False) + "\n").encode("utf-8")


def pretty_json_bytes(value: Any) -> bytes:
    return (json.dumps(value, indent=2, sort_keys=True, ensure_ascii=False) + "\n").encode("utf-8")


def sha256_bytes(data: bytes) -> str:
    return hashlib.sha256(data).hexdigest()


def line_map(text: str) -> list[str]:
    return text.splitlines()


def bounded_hits(text: str, terms: Iterable[str], *, max_hits: int = 80) -> list[dict[str, Any]]:
    lines = line_map(text)
    results: list[dict[str, Any]] = []
    for number, raw_line in enumerate(lines, 1):
        lowered = raw_line.casefold()
        matching = [term for term in terms if term.casefold() in lowered]
        if matching:
            results.append(
                {
                    "line": number,
                    "terms": sorted(matching),
                    "text": raw_line[:500],
                }
            )
            if len(results) >= max_hits:
                break
    return results


def parse_python(text: str, path: str) -> tuple[Optional[ast.Module], Optional[str]]:
    try:
        return ast.parse(text, filename=path), None
    except Exception as exc:
        return None, f"{type(exc).__name__}: {exc}"


def function_inventory(tree: Optional[ast.Module]) -> list[dict[str, Any]]:
    if tree is None:
        return []
    rows: list[dict[str, Any]] = []
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            rows.append(
                {
                    "name": node.name,
                    "line": node.lineno,
                    "end_line": getattr(node, "end_lineno", node.lineno),
                    "arguments": [arg.arg for arg in node.args.args],
                    "kind": "async" if isinstance(node, ast.AsyncFunctionDef) else "sync",
                }
            )
    rows.sort(key=lambda row: (row["line"], row["name"]))
    return rows


def call_inventory(tree: Optional[ast.Module], start: int, end: int) -> list[dict[str, Any]]:
    if tree is None:
        return []
    rows: list[dict[str, Any]] = []
    for node in ast.walk(tree):
        if not isinstance(node, ast.Call):
            continue
        if not (start <= getattr(node, "lineno", -1) <= end):
            continue
        func = node.func
        if isinstance(func, ast.Name):
            name = func.id
        elif isinstance(func, ast.Attribute):
            pieces: list[str] = []
            current: Any = func
            while isinstance(current, ast.Attribute):
                pieces.append(current.attr)
                current = current.value
            if isinstance(current, ast.Name):
                pieces.append(current.id)
            name = ".".join(reversed(pieces))
        else:
            name = type(func).__name__
        rows.append({"line": node.lineno, "call": name})
    rows.sort(key=lambda row: (row["line"], row["call"]))
    return rows


def source_excerpt(text: str, start: int, end: int) -> list[dict[str, Any]]:
    lines = line_map(text)
    lower = max(1, start)
    upper = min(len(lines), end)
    return [{"line": i, "text": lines[i - 1][:600]} for i in range(lower, upper + 1)]


def read_primary_inputs(project_root: Path) -> tuple[list[dict[str, Any]], dict[str, str]]:
    inventory: list[dict[str, Any]] = []
    texts: dict[str, str] = {}
    for logical_name, relative_path, required in PRIMARY_INPUT_SPECS:
        full_path = project_root / Path(relative_path)
        row: dict[str, Any] = {
            "logical_name": logical_name,
            "relative_path": relative_path,
            "path": str(full_path),
            "required": required,
            "exists": full_path.is_file(),
        }
        if not full_path.is_file():
            row.update(
                {
                    "size_bytes": None,
                    "sha256": None,
                    "utf8_decoded": False,
                    "python_parsed": None,
                    "json_parsed": None,
                    "error": "missing",
                }
            )
            inventory.append(row)
            continue

        data = full_path.read_bytes()
        row["size_bytes"] = len(data)
        row["sha256"] = sha256_bytes(data)
        try:
            text = data.decode("utf-8")
            row["utf8_decoded"] = True
            texts[logical_name] = text
        except UnicodeDecodeError as exc:
            row["utf8_decoded"] = False
            row["error"] = f"UnicodeDecodeError: {exc}"
            inventory.append(row)
            continue

        suffix = full_path.suffix.casefold()
        if suffix == ".py":
            tree, error = parse_python(text, str(full_path))
            row["python_parsed"] = tree is not None
            row["python_parse_error"] = error
            row["function_count"] = len(function_inventory(tree))
            row["json_parsed"] = None
        elif suffix == ".json":
            try:
                json.loads(text)
                row["json_parsed"] = True
                row["json_parse_error"] = None
            except Exception as exc:
                row["json_parsed"] = False
                row["json_parse_error"] = f"{type(exc).__name__}: {exc}"
            row["python_parsed"] = None
        else:
            row["python_parsed"] = None
            row["json_parsed"] = None
        inventory.append(row)
    return inventory, texts


def verify_reference(inventory: list[dict[str, Any]]) -> dict[str, Any]:
    by_name = {row["logical_name"]: row for row in inventory}
    manifest = by_name["reference_manifest"]
    guide = by_name["reference_guide"]
    manifest_match = manifest.get("sha256") == AUTHORITATIVE_REFERENCE["manifest"]["sha256"]
    guide_match = guide.get("sha256") == AUTHORITATIVE_REFERENCE["guide"]["sha256"]
    return {
        "manifest_sha256_expected": AUTHORITATIVE_REFERENCE["manifest"]["sha256"],
        "manifest_sha256_actual": manifest.get("sha256"),
        "manifest_verified": manifest_match,
        "guide_sha256_expected": AUTHORITATIVE_REFERENCE["guide"]["sha256"],
        "guide_sha256_actual": guide.get("sha256"),
        "guide_verified": guide_match,
        "reference_build_mission": AUTHORITATIVE_REFERENCE["reference_build_mission"],
        "reference_build_receipt_sha256": AUTHORITATIVE_REFERENCE["reference_build_receipt_sha256"],
        "all_verified": manifest_match and guide_match,
    }


def analyze_shared_adapter(text: str) -> dict[str, Any]:
    tree, parse_error = parse_python(text, "self_knowledge_chat_adapter_v1.py")
    functions = function_inventory(tree)
    route = next((row for row in functions if row["name"] == "route_message"), None)
    if route is None:
        return {
            "parsed": tree is not None,
            "parse_error": parse_error,
            "route_message_found": False,
            "function_inventory": functions,
            "blocker": "route_message_not_found",
        }

    start = int(route["line"])
    end = int(route["end_line"])
    route_lines = line_map(text)[start - 1:end]
    slash_lines = [
        start + index
        for index, line in enumerate(route_lines)
        if "startswith(\"/\")" in line or "startswith('/')" in line
    ]
    broker_lines = [
        start + index
        for index, line in enumerate(route_lines)
        if "broker_request" in line or "current_state_request_broker_v1" in line
    ]
    resource_lines = [
        start + index
        for index, line in enumerate(route_lines)
        if "resource" in line.casefold()
        and (
            "provider" in line.casefold()
            or "evidence" in line.casefold()
            or "render" in line.casefold()
        )
    ]
    catalog_lines = [
        start + index
        for index, line in enumerate(route_lines)
        if "_catalog_matches" in line
    ]
    normalize_lines = [
        start + index
        for index, line in enumerate(route_lines)
        if "_normalize_selectors" in line or "_deterministic_request_id" in line
    ]

    if slash_lines:
        proposed_after = max(slash_lines)
    else:
        proposed_after = start
    candidates_after_slash = sorted(
        line for line in (normalize_lines + resource_lines + catalog_lines) if line > proposed_after
    )
    proposed_before = candidates_after_slash[0] if candidates_after_slash else min(end, proposed_after + 1)

    return {
        "parsed": tree is not None,
        "parse_error": parse_error,
        "route_message_found": True,
        "route_message": route,
        "slash_command_lines": slash_lines,
        "existing_current_state_broker_lines": broker_lines,
        "historical_resource_or_render_lines": resource_lines,
        "catalog_match_lines": catalog_lines,
        "normalization_and_request_id_lines": normalize_lines,
        "proposed_integration_anchor": {
            "after_line": proposed_after,
            "before_line": proposed_before,
            "rule": (
                "After exact slash-command bypass and required request normalization, "
                "before historical resource-evidence loading/catalog matching."
            ),
        },
        "route_calls_in_order": call_inventory(tree, start, end),
        "route_excerpt": source_excerpt(
            text,
            max(start, proposed_after - 4),
            min(end, proposed_before + 8),
        ),
        "routing_term_hits": bounded_hits(text, ROUTING_TERMS),
        "function_inventory": functions,
    }


def analyze_surface(logical_name: str, text: str) -> dict[str, Any]:
    tree, parse_error = parse_python(text, logical_name)
    functions = function_inventory(tree)
    route_hits = bounded_hits(
        text,
        (
            "route_message(",
            "self_knowledge",
            "director",
            "department",
            "model",
            "slash",
            "authorization",
        ),
        max_hits=120,
    )
    return {
        "logical_name": logical_name,
        "parsed": tree is not None,
        "parse_error": parse_error,
        "route_message_call_lines": [
            row["line"] for row in route_hits if "route_message(" in row["text"]
        ],
        "bounded_route_hits": route_hits,
        "function_count": len(functions),
    }


def analyze_authorization(texts: Mapping[str, str]) -> dict[str, Any]:
    file_rows: list[dict[str, Any]] = []
    exact_broker_envelope_hits: list[dict[str, Any]] = []
    for logical_name in (
        "shared_adapter",
        "desktop_helper",
        "webui_helper",
        "desktop_source",
        "webui_source",
        "security_containment",
        "mission_director",
        "engineer_agent",
    ):
        text = texts.get(logical_name)
        if text is None:
            continue
        hits = bounded_hits(text, AUTHORIZATION_TERMS, max_hits=120)
        row = {
            "logical_name": logical_name,
            "hit_count": len(hits),
            "hits": hits,
        }
        file_rows.append(row)
        for hit in hits:
            hit_text = hit["text"].casefold()
            if (
                "allowed_categories" in hit_text
                or "allowed_provider_ids" in hit_text
                or "\"mode\": \"read_only\"" in hit_text
                or "'mode': 'read_only'" in hit_text
            ):
                exact_broker_envelope_hits.append(
                    {
                        "logical_name": logical_name,
                        "line": hit["line"],
                        "text": hit["text"],
                    }
                )

    adapter_text = texts.get("shared_adapter", "")
    adapter_tree, _ = parse_python(adapter_text, "shared_adapter")
    route_function = next(
        (
            row
            for row in function_inventory(adapter_tree)
            if row["name"] == "route_message"
        ),
        None,
    )
    route_arguments = route_function.get("arguments", []) if route_function else []
    route_accepts_explicit_authorization = any(
        "authoriz" in argument.casefold() for argument in route_arguments
    )

    suitable = bool(exact_broker_envelope_hits and route_accepts_explicit_authorization)
    if suitable:
        conclusion = "suitable_authorization_source_proven"
    else:
        conclusion = "no_suitable_current_state_authorization_source_proven"

    return {
        "conclusion": conclusion,
        "suitable_authorization_source_proven": suitable,
        "route_message_arguments": route_arguments,
        "route_message_accepts_explicit_authorization": route_accepts_explicit_authorization,
        "exact_broker_authorization_envelope_hits_outside_broker": exact_broker_envelope_hits,
        "bounded_file_findings": file_rows,
        "important_distinction": (
            "Engineering/department authorization tokens do not by themselves prove a "
            "request-scoped current-state authorization envelope containing read_only mode, "
            "allowed_categories, and allowed_provider_ids."
        ),
    }


def parse_contract(text: Optional[str]) -> dict[str, Any]:
    if not text:
        return {"available": False}
    try:
        value = json.loads(text)
    except Exception as exc:
        return {"available": True, "parsed": False, "error": f"{type(exc).__name__}: {exc}"}
    return {
        "available": True,
        "parsed": True,
        "schema": value.get("schema"),
        "mission_id": value.get("mission_id"),
        "scope": value.get("scope"),
        "statuses": value.get("statuses"),
        "authorization_contract": value.get("authorization_contract"),
        "provider_contract": value.get("provider_contract"),
    }


def build_outputs(project_root: Path) -> dict[str, bytes]:
    inventory_rows, texts = read_primary_inputs(project_root)
    missing_required = [
        row["relative_path"]
        for row in inventory_rows
        if row["required"] and not row["exists"]
    ]
    reference = verify_reference(inventory_rows)

    shared_findings = analyze_shared_adapter(texts.get("shared_adapter", ""))
    shared_findings.update(
        {
            "schema": f"{SCHEMA_PREFIX}.shared_router_findings.v1",
            "mission_id": MISSION_ID,
            "shared_adapter_path": str(
                project_root / "System/AgentFoxTechnicalCore/self_knowledge_chat_adapter_v1.py"
            ),
            "shared_adapter_sha256": next(
                (
                    row.get("sha256")
                    for row in inventory_rows
                    if row["logical_name"] == "shared_adapter"
                ),
                None,
            ),
            "desktop_helper": analyze_surface(
                "desktop_helper", texts.get("desktop_helper", "")
            ),
            "webui_helper": analyze_surface(
                "webui_helper", texts.get("webui_helper", "")
            ),
            "desktop_source": analyze_surface(
                "desktop_source", texts.get("desktop_source", "")
            ),
            "webui_source": analyze_surface(
                "webui_source", texts.get("webui_source", "")
            ),
            "reference_verified": reference["all_verified"],
        }
    )

    authorization = analyze_authorization(texts)
    authorization.update(
        {
            "schema": f"{SCHEMA_PREFIX}.authorization_findings.v1",
            "mission_id": MISSION_ID,
            "reference_verified": reference["all_verified"],
        }
    )

    contract_summary = parse_contract(texts.get("current_state_contract"))
    pass_through = {
        "schema": f"{SCHEMA_PREFIX}.pass_through_matrix.v1",
        "mission_id": MISSION_ID,
        "current_state_contract": contract_summary,
        "rows": list(PASS_THROUGH_ROWS),
        "historical_evidence_must_never_be_reused_as_current": True,
        "ordinary_chat_must_not_be_intercepted": True,
        "slash_commands_must_not_load_broker_or_providers": True,
    }

    existing_broker_calls = shared_findings.get("existing_current_state_broker_lines", [])
    blockers: list[str] = []
    if missing_required:
        blockers.append("required_primary_inputs_missing")
    if not reference["all_verified"]:
        blockers.append("authoritative_reference_hash_mismatch")
    if not shared_findings.get("route_message_found"):
        blockers.append("canonical_route_message_not_found")
    if existing_broker_calls:
        blockers.append("current_state_broker_already_present_in_shared_adapter")

    authorization_proven = authorization["suitable_authorization_source_proven"]
    recommendation_status = (
        "preflight_complete_ready_for_classification_only_integration"
        if not blockers
        else "preflight_blocked_for_exact_review"
    )
    recommendation = {
        "schema": f"{SCHEMA_PREFIX}.minimal_integration_recommendation.v1",
