        "recommended_next_stage": (
            "V1B-3C classification-only shared-router integration"
            if not blockers
            else "Resolve preflight blockers before integration"
        ),
        "authorization_source_proven": authorization_proven,
        "live_provider_registry_available": False,
        "integration_scope": {
            "modify_only_shared_adapter": True,
            "desktop_source_change_required": False,
            "webui_source_change_required": False,
