def write_outputs(project_root: Path, output_dir: Path) -> dict[str, Any]:
    outputs = build_outputs(project_root)
    first = {name: data for name, data in outputs.items()}
    second = build_outputs(project_root)
    if first != second:
        raise AssertionError("deterministic_rebuild_mismatch")

    output_dir.mkdir(parents=True, exist_ok=True)
    expected = set(EXPECTED_OUTPUT_NAMES)
    for name, data in outputs.items():
        if name not in expected:
            raise AssertionError(f"unexpected_output_name:{name}")
        target = output_dir / name
        target.write_bytes(data)

    actual = {path.name for path in output_dir.iterdir() if path.is_file()}
    allowed_non_outputs = {
        "v1b3b_shared_router_integration_preflight.py",
        "README_V1B3B.md",
    }
    unexpected = sorted(actual - expected - allowed_non_outputs)
    if unexpected:
        raise AssertionError(f"unexpected_files_in_output_dir:{unexpected}")

    return {
        "mission_id": MISSION_ID,
        "output_dir": str(output_dir),
        "output_count": len(outputs),
        "deterministic": True,
        "status": json.loads(outputs["V1B3B_PREFLIGHT_RECEIPT.json"])["status"],
    }


def self_test() -> dict[str, Any]:
    synthetic = """
def route_message(message, surface, request_id=None, selectors=None):
    normalized_message = str(message or "")
    if normalized_message.lstrip().startswith("/"):
        return pass_through()
    normalized_selectors = normalize(selectors)
    rid = request_id or make_id(normalized_message)
    bridge = load_bridge()
    candidates = _catalog_matches(normalized_message, normalized_selectors, bridge)
    return candidates
"""
    findings = analyze_shared_adapter(synthetic)
    assert findings["route_message_found"]
    assert findings["slash_command_lines"]
    assert findings["catalog_match_lines"]
    anchor = findings["proposed_integration_anchor"]
    assert anchor["after_line"] < anchor["before_line"]

    auth = analyze_authorization(
        {
            "shared_adapter": synthetic,
            "webui_source": (
                "authorization = direct_mission(text)\n"
                "read_only_allowed = True\n"
                "operator_approved = True\n"
            ),
        }
    )
    assert auth["suitable_authorization_source_proven"] is False
    assert auth["conclusion"] == "no_suitable_current_state_authorization_source_proven"
    return {
        "schema": f"{SCHEMA_PREFIX}.self_test.v1",
        "mission_id": MISSION_ID,
        "passed": True,
        "tests": 8,
    }


def main(argv: Optional[list[str]] = None) -> int:
    parser = argparse.ArgumentParser(description="V1B-3B shared-router integration preflight")
    parser.add_argument("--project-root")
    parser.add_argument("--output-dir")
    parser.add_argument("--self-test", action="store_true")
    args = parser.parse_args(argv)

    if args.self_test:
        print(json.dumps(self_test(), indent=2, sort_keys=True))
        return 0

    if not args.project_root or not args.output_dir:
        parser.error("--project-root and --output-dir are required unless --self-test is used")

    project_root = Path(args.project_root)
    output_dir = Path(args.output_dir)
    result = write_outputs(project_root, output_dir)
    print(json.dumps(result, indent=2, sort_keys=True))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
